              <Users className="w-4 h-4 text-[var(--color-meza-primary)]" />
              <h3 className="font-bold text-blue-900 tracking-tight text-sm">Active Staff on Duty</h3>
            </div>
            <div className="p-2">
              {data.activeShifts.length > 0 ? (
                <div className="space-y-1">
                  {data.activeShifts.map((shift, i) => (
                    <div key={i} className="flex items-center justify-between p-3 rounded-sm hover:bg-[var(--color-meza-bg)] transition-colors">
                      <div className="flex items-center space-x-3">
                        <div className="w-8 h-8 rounded-full bg-[var(--color-meza-primary)]/20 text-[var(--color-meza-primary)] flex items-center justify-center font-bold text-xs">
                          {shift.staffName.charAt(0)}
                        </div>
                        <div>
                          <p className="font-bold text-[var(--color-meza-text)] text-sm leading-tight">{shift.staffName}</p>
                          <p className="text-[10px] font-bold text-[var(--color-meza-muted)] uppercase tracking-wider">POS Register Active</p>
                        </div>
                      </div>
                      <div className="text-right">
                        <p className="text-[10px] font-bold text-[var(--color-meza-muted)] uppercase tracking-wider mb-0.5">Exp. Cash</p>
                        <p className="font-bold text-[var(--color-meza-text)] text-sm">₱{(shift.expectedCash || 0).toFixed(2)}</p>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="p-4 text-center">
                  <p className="text-sm font-medium text-[var(--color-meza-muted)]">No active shifts right now.</p>
                </div>
              )}
            </div>
          </div>

          {/* Low Stock Alerts */}
          <div className="bg-[var(--color-meza-surface)] rounded-sm shadow-[0_4px_20px_rgb(0,0,0,0.02)] border border-[var(--color-meza-border)] overflow-hidden">
            <div className="p-4 border-b border-[var(--color-meza-border)] flex justify-between items-center bg-[var(--color-danger)]/10/30">
              <div className="flex items-center space-x-2">
                <AlertTriangle className="w-4 h-4 text-[var(--color-danger)]" />
                <h3 className="font-bold text-red-900 tracking-tight text-sm">Low Stock Alerts</h3>
              </div>
              {data.lowStockItems.length > 0 && (
                <span className="bg-[var(--color-danger)]/20 text-[var(--color-danger)] text-[10px] font-bold px-2 py-0.5 rounded-md">{data.lowStockItems.length} Warnings</span>
              )}
            </div>
            <div className="p-2">
              {data.lowStockItems.length > 0 ? (
                <div className="space-y-1">
                  {data.lowStockItems.map(item => (
                    <div key={item._id} className="flex items-center justify-between p-3 rounded-sm hover:bg-[var(--color-meza-bg)] transition-colors group">
                      <div className="flex items-center space-x-3">
                        <div className={`w-8 h-8 rounded-sm flex items-center justify-center ${item.stock <= 0 ? 'bg-[var(--color-danger)]/10 text-[var(--color-danger)]' : 'bg-[var(--color-warning)]/10 text-[var(--color-warning)]'}`}>
                          <PackageCheck className="w-4 h-4" />
                        </div>
                        <div>
                          <p className="font-bold text-[var(--color-meza-text)] text-sm leading-tight">{item.name}</p>
                          <p className="text-[10px] font-bold text-[var(--color-meza-muted)] uppercase tracking-wider">{item.type}</p>
                        </div>
                      </div>
                      <div className="text-right">
                        <span className={`inline-flex items-center px-2 py-1 rounded border text-xs font-bold ${item.stock <= 0 ? 'bg-[var(--color-danger)]/10 text-[var(--color-danger)] border-[var(--color-danger)]/30' : 'bg-[var(--color-warning)]/10 text-[var(--color-warning)] border-[var(--color-warning)]/30'}`}>
                          {item.stock} left
                        </span>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="p-6 text-center">
                  <PackageCheck className="w-8 h-8 text-green-400 mx-auto mb-2" />
                  <p className="text-sm font-bold text-[var(--color-meza-text)]">All Stock Healthy</p>
                  <p className="text-xs font-medium text-[var(--color-meza-muted)] mt-1">No items require reordering right now.</p>
                </div>
              )}
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { PackageCheck, AlertTriangle, Search, ArrowUp, ArrowDown, X, Coffee, Layers, Tag, Beaker, Upload, History, Trash2 } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import MenuItemModal from '../../components/admin/MenuItemModal';
import Papa from 'papaparse';

export default function InventoryManagement() {
  const { token } = useAuth();

  const [activeTab, setActiveTab] = useState('finished'); // 'finished' | 'raw' | 'history'

  const [menuItems, setMenuItems] = useState([]);
  const [ingredients, setIngredients] = useState([]);
  const [historyData, setHistoryData] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const fileInputRef = React.useRef(null);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isDeliveryModalOpen, setIsDeliveryModalOpen] = useState(false);
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [isRecipeModalOpen, setIsRecipeModalOpen] = useState(false);
  const [isMenuModalOpen, setIsMenuModalOpen] = useState(false);

  const [currentItem, setCurrentItem] = useState(null);
  const [recipeData, setRecipeData] = useState(null);

  const [adjustAmount, setAdjustAmount] = useState('');
  const [adjustType, setAdjustType] = useState('add');
  const [adjustReason, setAdjustReason] = useState('Count Correction');
  const [deliveryData, setDeliveryData] = useState({ quantity: '', totalCost: '', supplier: '', invoiceId: '' });
  const [createData, setCreateData] = useState({});

  const fetchData = () => {
    fetch(`${import.meta.env.VITE_API_URL || (import.meta.env.VITE_API_URL || 'http://localhost:5001')}/api/menu`, { headers: { 'Authorization': `Bearer ${token}` } })
      .then(res => res.ok ? res.json() : Promise.reject(new Error(res.statusText)))
      .then(setMenuItems)
      .catch(console.error);

    fetch(`${import.meta.env.VITE_API_URL || 'http://localhost:5001'}/api/inventory`, { headers: { 'Authorization': `Bearer ${token}` } })
      .then(res => res.ok ? res.json() : Promise.reject(new Error(res.statusText)))
      .then(setIngredients)
      .catch(console.error);

    fetch(`${import.meta.env.VITE_API_URL || 'http://localhost:5001'}/api/inventory/history`, { headers: { 'Authorization': `Bearer ${token}` } })
      .then(res => res.ok ? res.json() : Promise.reject(new Error(res.statusText)))
      .then(setHistoryData)
      .catch(console.error);
  };

  useEffect(() => {
    if (token) fetchData();
  }, [token]);

  const openAdjustModal = (item) => {
    setCurrentItem(item);
    setAdjustAmount('');
    setAdjustType('add');
    setAdjustReason('Count Correction');
    setIsModalOpen(true);
  };

  const openDeliveryModal = (item) => {
    setCurrentItem(item);
    setDeliveryData({ quantity: '', totalCost: '', supplier: '', invoiceId: '' });
    setIsDeliveryModalOpen(true);
  };

  const openCreateModal = () => {
    setCreateData(activeTab === 'finished' ? {
      name: '', category: 'Food', price: '', stockQuantity: 0, lowStockThreshold: 5
    } : {
      name: '', purchaseUnit: 'kg', unitCost: '', stockQuantity: 0, lowStockThreshold: 5
    });
    setIsCreateModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setIsDeliveryModalOpen(false);
    setIsCreateModalOpen(false);
    setIsRecipeModalOpen(false);
    setIsMenuModalOpen(false);
    setCurrentItem(null);
    setRecipeData(null);
  };

  const handleAdjustStock = async (e) => {
    e.preventDefault();
    const amount = parseFloat(adjustAmount);
    if (isNaN(amount) || amount <= 0) return alert("Enter a valid amount.");

    const newStock = adjustType === 'add'
      ? (currentItem.stockQuantity || 0) + amount
      : (currentItem.stockQuantity || 0) - amount;

    if (newStock < 0) return alert("Stock cannot be negative.");

    const isRaw = activeTab === 'raw';
    const endpoint = isRaw ? `${import.meta.env.VITE_API_URL || `${import.meta.env.VITE_API_URL || (import.meta.env.VITE_API_URL || 'http://localhost:5001')}`}/api/inventory/${currentItem._id}` : `${import.meta.env.VITE_API_URL || `${import.meta.env.VITE_API_URL || (import.meta.env.VITE_API_URL || 'http://localhost:5001')}`}/api/menu/${currentItem._id}`;

    try {
      const payload = isRaw ? {
        name: currentItem.name,
        purchaseUnit: currentItem.purchaseUnit,
        unitCost: currentItem.unitCost,
        currency: currentItem.currency || 'PHP',
        lowStockThreshold: currentItem.lowStockThreshold || 5,
        stockQuantity: newStock,
        reason: adjustReason
      } : { stockQuantity: newStock, reason: adjustReason };

      const res = await fetch(endpoint, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify(payload)
      });
      if (res.ok) {
        fetchData();
        handleCloseModal();
      } else {
        alert("Failed to adjust stock.");
      }
    } catch (err) { console.error(err); }
  };

  const handleReceiveDelivery = async (e) => {
    e.preventDefault();
    const qty = parseFloat(deliveryData.quantity);
    const cost = parseFloat(deliveryData.totalCost);

    if (isNaN(qty) || qty <= 0 || isNaN(cost) || cost <= 0) {
      return alert("Please enter valid quantities and costs.");
    }

    try {
      const res = await fetch(`${import.meta.env.VITE_API_URL || (import.meta.env.VITE_API_URL || 'http://localhost:5001')}/api/inventory/purchase`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({
          ingredientId: currentItem._id,
          quantityReceived: qty,
          totalCostPaid: cost,
          supplierName: deliveryData.supplier,
          invoiceId: deliveryData.invoiceId
        })
      });
      if (res.ok) {
        fetchData();
        handleCloseModal();
      } else {
        alert("Failed to record delivery.");
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleDeleteItem = async (item) => {
    if (!window.confirm(`Are you sure you want to delete ${item.name}?`)) return;
    const isRaw = activeTab === 'raw';
    const endpoint = isRaw ? `${import.meta.env.VITE_API_URL || 'http://localhost:5001'}/api/inventory/${item._id}` : `${import.meta.env.VITE_API_URL || 'http://localhost:5001'}/api/menu/${item._id}`;

    try {
      const res = await fetch(endpoint, {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      if (res.ok) {
        fetchData();
      } else {
        alert("Failed to delete item.");
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    const isRaw = activeTab === 'raw';
    const endpoint = isRaw ? `${import.meta.env.VITE_API_URL || (import.meta.env.VITE_API_URL || 'http://localhost:5001')}/api/inventory` : `${import.meta.env.VITE_API_URL || (import.meta.env.VITE_API_URL || 'http://localhost:5001')}/api/menu`;

    const payload = { ...createData };
    if (!isRaw) payload.price = parseFloat(payload.price) || 0;
    if (isRaw) payload.unitCost = parseFloat(payload.unitCost) || 0;
    payload.stockQuantity = parseFloat(payload.stockQuantity) || 0;
    payload.lowStockThreshold = parseFloat(payload.lowStockThreshold) || 0;

    try {
      const res = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
        body: JSON.stringify(payload)
      });
      if (res.ok) {
        fetchData();
        handleCloseModal();
      } else {
        const errorData = await res.json();
        alert(`Failed to create: ${errorData.message || 'Unknown error'}`);
      }
    } catch (err) { console.error(err); }
  };

  const handleImportCSV = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    Papa.parse(file, {
      header: true,
      skipEmptyLines: true,
      complete: async (results) => {
        const items = results.data.map(row => ({
          name: row['Name'] || row['name'],
          purchaseUnit: row['Purchase Unit'] || row['purchaseUnit'] || row['Unit'] || 'pcs',
          unitCost: parseFloat(row['Unit Cost'] || row['unitCost'] || 0),
          stockQuantity: parseFloat(row['Initial Stock'] || row['stockQuantity'] || 0),
          lowStockThreshold: parseFloat(row['Low Par Alert'] || row['lowStockThreshold'] || 5)
        })).filter(i => i.name);

        if (items.length === 0) {
          return alert('No valid items found in CSV. Please check headers.');
        }

        try {
          const res = await fetch(`${import.meta.env.VITE_API_URL || 'http://localhost:5001'}/api/inventory/import`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
            body: JSON.stringify({ items })
          });
          if (res.ok) {
            const data = await res.json();
            alert(`Import complete: ${data.added} added, ${data.updated} updated. Errors: ${data.errors.length}`);
            fetchData();
          } else {
            alert('Import failed.');
          }
        } catch (err) {
          console.error(err);
          alert('Import failed due to server error.');
        }
      }
    });
    // Reset file input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const openRecipeCosting = async (item) => {
    setCurrentItem(item);
    setIsRecipeModalOpen(true);
    setRecipeData(null); // loading state

    let sizeQuery = '';
    if (item.sizes && item.sizes.length > 0) {
      sizeQuery = `?size=${encodeURIComponent(item.sizes[0].name)}`;
    }

    try {
      const res = await fetch(`${import.meta.env.VITE_API_URL || 'http://localhost:5001'}/api/menu/${item._id}/recipe-costing${sizeQuery}`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setRecipeData(data);
      } else {
        setRecipeData({ error: true, status: res.status });
      }
    } catch (err) {
      console.error(err);
    }
  };

  // Processing Data for view
  const currentList = activeTab === 'finished' ? menuItems : ingredients;
  const filteredItems = currentList.filter(i => i.name.toLowerCase().includes(searchQuery.toLowerCase()));

  // Grouping for Finished Goods
  const groupedMenu = menuItems.filter(i => i.name.toLowerCase().includes(searchQuery.toLowerCase())).reduce((acc, item) => {
    const cat = item.category || 'Uncategorized';
    if (!acc[cat]) acc[cat] = [];
    acc[cat].push(item);
    return acc;
  }, {});

  const uniqueUnits = [...new Set(ingredients.map(i => i.purchaseUnit).filter(Boolean))];

  return (
    <div className="space-y-6 relative">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-[var(--color-meza-text)] tracking-tight">Inventory Management</h2>
