                    <th className="px-6 py-4">Ingredient</th>
                    <th className="px-6 py-4 text-right">Quantity</th>
                    <th className="px-6 py-4 text-right">Details/Cost</th>
                    <th className="px-6 py-4">Actor</th>
                  </tr>
                </thead>
