                            <div className={`h-full rounded-full ${stock <= 0 ? 'bg-[var(--color-danger)]/100' : isLowStock ? 'bg-[var(--color-warning)]/100' : 'bg-[var(--color-success)]/100'}`} style={{ width: `${stock <= 0 ? 100 : progressPercent}%` }}></div>
                          </div>
                        </div>
