                    <ArrowDown className="w-4 h-4" /><span>Subtract</span>
                  </button>
                </div>

                <div>
                  <label className="block text-[11px] font-bold text-[var(--color-meza-muted)] uppercase tracking-wider mb-1.5">Amount to {adjustType}</label>
