                    <span className="absolute right-4 top-1/2 -translate-y-1/2 text-sm font-bold text-[var(--color-meza-muted)] uppercase">{activeTab === 'raw' ? currentItem.purchaseUnit : 'units'}</span>
                  </div>
                </div>

