                              <th className="py-2 px-3 text-right font-bold uppercase">Qty</th>
                              <th className="py-2 px-3 text-right font-bold uppercase">Cost</th>
                            </tr>
                          </thead>
                          <tbody className="divide-y divide-gray-100">
