      <MenuItemModal 
        isOpen={isMenuModalOpen} 
        onClose={() => {
          setIsMenuModalOpen(false);
          if (currentItem) openRecipeCosting(currentItem); // refresh recipe data
        }} 
        initialData={currentItem}
        rawIngredients={ingredients}
        token={token}
        onSuccess={fetchData}
      />
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Plus, Edit2, Archive, CheckCircle, XCircle } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import MenuItemModal from '../../components/admin/MenuItemModal';

export default function MenuManagement() {
  const { token } = useAuth();
  const [items, setItems] = useState([]);
  const [rawIngredients, setRawIngredients] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState(null);

  // Archive Modal State
  const [isArchiveModalOpen, setIsArchiveModalOpen] = useState(false);
  const [itemToArchive, setItemToArchive] = useState(null);
  const [isArchiving, setIsArchiving] = useState(false);

  const fetchMenu = () => {
    fetch(`${import.meta.env.VITE_API_URL || 'http://localhost:5001'}/api/menu`, {
      headers: { 'Authorization': `Bearer ${token}` }
    })
      .then(res => res.ok ? res.json() : Promise.reject(new Error(res.statusText)))
      .then(setItems)
      .catch(console.error);

    fetch(`${import.meta.env.VITE_API_URL || 'http://localhost:5001'}/api/inventory`, {
      headers: { 'Authorization': `Bearer ${token}` }
    })
      .then(res => res.ok ? res.json() : Promise.reject(new Error(res.statusText)))
      .then(setRawIngredients)
      .catch(console.error);
  };

  useEffect(() => {
    if (token) fetchMenu();
  }, [token]);

  const handleToggleStatus = async (item) => {
    try {
      await fetch(`${import.meta.env.VITE_API_URL || `${import.meta.env.VITE_API_URL || (import.meta.env.VITE_API_URL || 'http://localhost:5001')}`}/api/menu/${item._id}`, {
        method: 'PUT',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ isAvailable: !item.isAvailable })
      });
      fetchMenu();
    } catch (err) {
      console.error(err);
    }
  };

  const handleAddItem = () => {
    setEditingItem(null);
    setIsModalOpen(true);
  };

  const handleEditItem = (item) => {
    setEditingItem(item);
    setIsModalOpen(true);
  };

  const openArchiveModal = (item) => {
    setItemToArchive(item);
    setIsArchiveModalOpen(true);
  };

  const confirmArchiveItem = async () => {
    if (!itemToArchive) return;
    setIsArchiving(true);
    try {
      await fetch(`${import.meta.env.VITE_API_URL || 'http://localhost:5001'}/api/menu/${itemToArchive._id}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` }
      });
      // Optimistic update
      setItems(items.filter(i => i._id !== itemToArchive._id));
      setIsArchiveModalOpen(false);
      setItemToArchive(null);
    } catch (err) {
      console.error(err);
      alert('Failed to archive item.');
    } finally {
      setIsArchiving(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-[var(--color-meza-text)] tracking-tight">Menu Management</h2>
          <p className="text-[var(--color-meza-muted)] text-sm mt-1">Manage your items, prices, and live availability.</p>
        </div>
        <button onClick={handleAddItem} className="bg-meza-text hover:bg-[var(--color-meza-primary)] text-white px-4 py-2 rounded-sm flex items-center space-x-2 font-semibold text-sm transition-colors  active:scale-[0.98] cursor-pointer">
          <Plus className="w-4 h-4" strokeWidth={2.5} />
          <span>Add Menu Item</span>
        </button>
      </div>

      <div className="bg-[var(--color-meza-surface)] rounded-sm shadow-[0_2px_10px_rgb(0,0,0,0.02)] border border-[var(--color-meza-border)] overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm min-w-[700px]">
            <thead className="bg-[var(--color-meza-bg)] border-b border-[var(--color-meza-border)] text-[var(--color-meza-muted)] text-xs font-semibold uppercase tracking-wider">
            <tr>
              <th className="px-6 py-4">Item Name</th>
              <th className="px-6 py-4">Category</th>
              <th className="px-6 py-4">Price (₱)</th>
              <th className="px-6 py-4">Status</th>
              <th className="px-6 py-4 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {items.map(item => (
              <tr key={item._id} className="hover:bg-[var(--color-meza-bg)] transition-colors">
                <td className="px-6 py-4">
                  <div className="flex items-center space-x-3">
                    <img src={item.photoUrl || "https://images.unsplash.com/photo-1546069901-ba9599a7e63c"} alt="" className="w-10 h-10 rounded-sm object-cover bg-[var(--color-meza-bg)]" />
                    <span className="font-semibold text-[var(--color-meza-text)]">{item.name}</span>
                  </div>
                </td>
                <td className="px-6 py-4 text-[var(--color-meza-muted)] font-medium">{item.category}</td>
                <td className="px-6 py-4 font-bold text-[var(--color-meza-text)]">
                  {item.sizes && item.sizes.length > 0 ? (
                    <span>From ₱{Math.min(...item.sizes.map(s => s.price || 0)).toFixed(2)}</span>
                  ) : (
                    <span>₱{(item.price || 0).toFixed(2)}</span>
                  )}
                </td>
                <td className="px-6 py-4">
                  <button 
                    onClick={() => handleToggleStatus(item)}
                    className={`inline-flex items-center space-x-1.5 px-2.5 py-1 rounded-md text-[11px] font-bold uppercase tracking-wide border cursor-pointer transition-all active:scale-95 ${item.isAvailable ? 'bg-[var(--color-success)]/10/80 text-[var(--color-success)] border-[var(--color-success)]/30/60 hover:bg-[var(--color-danger)]/10 hover:text-[var(--color-danger)] hover:border-[var(--color-danger)]/30' : 'bg-[var(--color-danger)]/10/80 text-[var(--color-danger)] border-[var(--color-danger)]/30/60 hover:bg-[var(--color-success)]/10 hover:text-[var(--color-success)] hover:border-[var(--color-success)]/30'}`}
                    title="Click to toggle availability"
                  >
                    {item.isAvailable ? <CheckCircle className="w-3 h-3" strokeWidth={3} /> : <XCircle className="w-3 h-3" strokeWidth={3} />}
                    <span>{item.isAvailable ? 'Available' : 'Sold Out'}</span>
                  </button>
                </td>
                <td className="px-6 py-4 text-right space-x-1">
                  <button onClick={() => handleEditItem(item)} className="p-1.5 text-[var(--color-meza-muted)] hover:text-[var(--color-meza-primary)] hover:bg-[var(--color-meza-primary)]/5 rounded-md transition-colors cursor-pointer" title="Edit Item">
                    <Edit2 className="w-4 h-4" />
                  </button>
                  <button onClick={() => openArchiveModal(item)} className="p-1.5 text-[var(--color-meza-muted)] hover:text-[var(--color-danger)] hover:bg-[var(--color-danger)]/10 rounded-md transition-colors cursor-pointer" title="Archive Item">
                    <Archive className="w-4 h-4" />
                  </button>
                </td>
              </tr>
            ))}
            {items.length === 0 && (
              <tr>
                <td colSpan="5" className="px-6 py-12 text-center text-[var(--color-meza-muted)] font-medium text-sm">
                  No menu items found.
                </td>
              </tr>
            )}
          </tbody>
          </table>
        </div>
      </div>

      <MenuItemModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        initialData={editingItem}
        rawIngredients={rawIngredients}
        token={token}
        onSuccess={fetchMenu}
      />

      {/* Archive Confirmation Modal */}
      {isArchiveModalOpen && itemToArchive && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-lg shadow-xl w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6">
              <div className="flex items-center justify-center w-12 h-12 rounded-full bg-[var(--color-danger)]/10 mx-auto mb-4">
                <Archive className="w-6 h-6 text-[var(--color-danger)]" />
              </div>
              <h3 className="text-xl font-bold text-center text-[var(--color-meza-text)] mb-2">Archive Item?</h3>
              <p className="text-center text-[var(--color-meza-muted)] text-sm mb-6">
                Are you sure you want to archive <strong>{itemToArchive.name}</strong>? It will be hidden from the menu, and its recipes will be removed.
              </p>
              <div className="flex space-x-3">
                <button 
                  onClick={() => setIsArchiveModalOpen(false)}
                  disabled={isArchiving}
                  className="flex-1 px-4 py-2 bg-[var(--color-meza-bg)] text-[var(--color-meza-text)] hover:bg-[var(--color-meza-border)] rounded-sm font-bold transition-colors disabled:opacity-50"
                >
                  Cancel
                </button>
                <button 
                  onClick={confirmArchiveItem}
                  disabled={isArchiving}
                  className="flex-1 px-4 py-2 bg-[var(--color-danger)] text-white hover:bg-red-700 rounded-sm font-bold transition-colors disabled:opacity-50 flex items-center justify-center"
                >
                  {isArchiving ? (
                    <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                  ) : (
                    'Archive'
                  )}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Tag, ChevronDown, ChevronUp, Beaker, Plus, Trash2, Save, Calculator } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';

export default function RecipeCalculator() {
  const { token } = useAuth();
  const [marginsData, setMarginsData] = useState([]);
  const [rawIngredients, setRawIngredients] = useState([]);
  const [expandedItem, setExpandedItem] = useState(null);

  // Sandbox State
  const [sandboxItem, setSandboxItem] = useState(null);
  const [sandboxIngredients, setSandboxIngredients] = useState([]);
  const [isSaving, setIsSaving] = useState(false);

  const fetchData = () => {
    if (!token) return;

    // Fetch Server-Calculated Margins with ingredientsBreakdown
    fetch(`${import.meta.env.VITE_API_URL || 'http://localhost:5001'}/api/analytics/margins`, { 
      headers: { 'Authorization': `Bearer ${token}` } 
    })
      .then(r => r.json())
      .then(setMarginsData)
      .catch(console.error);

    // Fetch Raw Ingredients for Sandbox
    fetch(`${import.meta.env.VITE_API_URL || 'http://localhost:5001'}/api/inventory`, { 
      headers: { 'Authorization': `Bearer ${token}` } 
    })
      .then(r => r.json())
      .then(setRawIngredients)
      .catch(console.error);
  };

  useEffect(() => {
    fetchData();
  }, [token]);

  const getMarginColor = (marginPercent) => {
    if (marginPercent >= 70) return 'bg-[var(--color-success)]/10/80 text-[var(--color-success)] border-[var(--color-success)]/30/60';
    if (marginPercent >= 50) return 'bg-[var(--color-warning)]/10/80 text-[var(--color-warning)] border-[var(--color-warning)]/30/60';
    return 'bg-[var(--color-danger)]/10/80 text-[var(--color-danger)] border-[var(--color-danger)]/30/60';
  };

  const toggleExpand = (item) => {
    if (expandedItem === item._id) {
      setExpandedItem(null);
      setSandboxItem(null);
      setSandboxIngredients([]);
    } else {
      setExpandedItem(item._id);
      setSandboxItem(item);
      if (item.ingredientsBreakdown) {
        setSandboxIngredients(item.ingredientsBreakdown.map(ing => ({
          ingredientId: ing.ingredientId,
          quantity: ing.quantity,
          unit: ing.unit,
          name: ing.name,
          cost: ing.cost
        })));
      } else {
        setSandboxIngredients([]);
      }
    }
  };

  // --- Sandbox Logic ---
  const handleAddSandboxIngredient = () => {
    setSandboxIngredients([...sandboxIngredients, { ingredientId: '', quantity: '', unit: 'g', cost: 0 }]);
  };

  const handleRemoveSandboxIngredient = (index) => {
    setSandboxIngredients(sandboxIngredients.filter((_, i) => i !== index));
  };

  const handleSandboxChange = (index, field, value) => {
    const newIngs = [...sandboxIngredients];
    newIngs[index][field] = value;

    if (field === 'ingredientId') {
      const selectedRaw = rawIngredients.find(r => r._id === value);
      if (selectedRaw) {
        newIngs[index].name = selectedRaw.name;
        const pUnit = (selectedRaw.purchaseUnit || '').toLowerCase();
        if (pUnit === 'kg') newIngs[index].unit = 'g';
        else if (pUnit === 'l' || pUnit === 'liter') newIngs[index].unit = 'ml';
        else newIngs[index].unit = selectedRaw.purchaseUnit || 'g';
      }
    }
    setSandboxIngredients(newIngs);
  };

  // Compute Live Sandbox COGS
  const computeSandboxCOGS = () => {
    let totalCogs = 0;
    sandboxIngredients.forEach(ing => {
      if (!ing.ingredientId || !ing.quantity) return;
      const raw = rawIngredients.find(r => r._id === ing.ingredientId);
      if (raw) {
        let qty = parseFloat(ing.quantity);
        if (isNaN(qty)) qty = 0;

        let multiplier = 1;
        const pUnit = (raw.purchaseUnit || '').toLowerCase();
        const uUnit = (ing.unit || '').toLowerCase();

        if (pUnit === 'kg' && uUnit === 'g') multiplier = 1/1000;
        else if ((pUnit === 'l' || pUnit === 'liter') && uUnit === 'ml') multiplier = 1/1000;

        const unitPrice = raw.movingAverageCost || raw.unitCost || 0;
        totalCogs += (qty * multiplier * unitPrice);
      }
    });
    return totalCogs;
  };

  const sandboxCOGS = computeSandboxCOGS();
  const sandboxMargin = sandboxItem ? (sandboxItem.sellPrice > 0 ? ((sandboxItem.sellPrice - sandboxCOGS) / sandboxItem.sellPrice) * 100 : 0) : 0;

  const handleSaveRecipe = async () => {
    if (!sandboxItem) return;
    setIsSaving(true);
    try {
      const validIngredients = sandboxIngredients.filter(i => i.ingredientId && parseFloat(i.quantity) > 0);

      const res = await fetch(`${import.meta.env.VITE_API_URL || 'http://localhost:5001'}/api/recipes`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
        body: JSON.stringify({
          menuItemId: sandboxItem._id,
          ingredients: validIngredients.map(i => ({
            ingredientId: i.ingredientId,
            quantity: parseFloat(i.quantity),
            unit: i.unit
          }))
        })
      });

      if (!res.ok) throw new Error('Failed to save recipe');

      alert('Recipe Saved Successfully!');
      fetchData(); // Refresh list to get updated margins
    } catch (err) {
      alert(err.message);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-2xl font-bold text-[var(--color-meza-text)] tracking-tight">Recipe Cost Calculator</h2>
        <p className="text-[var(--color-meza-muted)] text-sm mt-1">Live COGS computation, interactive recipe testing, and margin analysis.</p>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">

        {/* LEFT COLUMN: INTERACTIVE RECIPE SANDBOX */}
        <div className="bg-[var(--color-meza-surface)] p-6 rounded-sm shadow-[0_2px_10px_rgb(0,0,0,0.02)] border border-[var(--color-meza-border)] flex flex-col h-[600px]">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-sm font-bold text-[var(--color-meza-text)] flex items-center space-x-2 uppercase tracking-wider">
              <Calculator className="w-4 h-4 text-[var(--color-meza-primary)]" />
              <span>Interactive Recipe Sandbox</span>
            </h3>
            {sandboxItem && (
              <button 
                onClick={handleSaveRecipe}
                disabled={isSaving}
                className="bg-meza-text hover:bg-black text-white px-3 py-1.5 rounded-sm text-xs font-bold flex items-center space-x-1.5 transition-colors disabled:opacity-50"
              >
                <Save className="w-3.5 h-3.5" />
                <span>{isSaving ? 'Saving...' : 'Save Recipe'}</span>
              </button>
            )}
          </div>

          {!sandboxItem ? (
            <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-[var(--color-meza-border)] rounded-sm bg-[var(--color-meza-bg)]/50">
              <Beaker className="w-12 h-12 text-[var(--color-meza-muted)] mb-3" />
              <p className="font-bold text-[var(--color-meza-muted)]">No Item Selected</p>
              <p className="text-xs text-[var(--color-meza-muted)] mt-1">Select an item from the right to build its recipe.</p>
            </div>
          ) : (
            <div className="flex-1 flex flex-col overflow-hidden">
              <div className="flex items-center justify-between mb-4 pb-4 border-b border-[var(--color-meza-border)] shrink-0">
                <div>
                  <h4 className="font-bold text-lg text-[var(--color-meza-text)]">{sandboxItem.name}</h4>
                  <p className="text-xs font-bold text-[var(--color-meza-muted)] uppercase tracking-widest mt-0.5">Sell Price: ₱{sandboxItem.sellPrice.toFixed(2)}</p>
                </div>
                <div className="text-right">
                  <div className="text-xs font-bold text-[var(--color-meza-muted)] uppercase tracking-widest">Live COGS</div>
                  <div className="font-bold text-xl text-[var(--color-meza-text)]">₱{sandboxCOGS.toFixed(2)}</div>
                  <div className={`mt-1 inline-flex items-center px-2 py-0.5 rounded-md text-[10px] font-bold uppercase tracking-wide border ${getMarginColor(sandboxMargin)}`}>
                    Margin: {sandboxMargin.toFixed(1)}%
                  </div>
                </div>
              </div>

              <div className="flex justify-between items-center mb-3 shrink-0">
                <span className="text-xs font-bold text-[var(--color-meza-muted)] uppercase tracking-wider">Ingredients List</span>
                <button 
                  onClick={handleAddSandboxIngredient}
                  className="text-xs font-bold text-[var(--color-meza-primary)] hover:bg-[var(--color-meza-primary)]/10 px-2.5 py-1 rounded-md flex items-center space-x-1 transition-colors"
                >
                  <Plus className="w-3 h-3" /><span>Add Ingredient</span>
                </button>
              </div>

              <div className="flex-1 overflow-y-auto space-y-3 pr-2 custom-scrollbar">
                {sandboxIngredients.length === 0 ? (
                  <p className="text-center text-sm font-medium text-[var(--color-meza-muted)] italic py-6">No ingredients added yet.</p>
                ) : (
                  sandboxIngredients.map((ing, idx) => (
                    <div key={idx} className="flex items-center space-x-2 bg-[var(--color-meza-bg)] p-2.5 rounded-sm border border-[var(--color-meza-border)] ">
                      <div className="flex-1">
                        <select 
                          value={ing.ingredientId || ''} 
                          onChange={e => handleSandboxChange(idx, 'ingredientId', e.target.value)}
                          className="w-full px-2 py-1.5 bg-[var(--color-meza-surface)] border border-[var(--color-meza-border)] rounded-sm outline-none focus:border-[var(--color-meza-primary)] font-semibold text-xs"
                        >
                          <option value="">-- Select Raw Ingredient --</option>
                          {rawIngredients.map(r => (
                            <option key={r._id} value={r._id}>{r.name} (₱{(r.movingAverageCost || r.unitCost).toFixed(2)}/{r.purchaseUnit})</option>
                          ))}
                        </select>
                      </div>
                      <div className="w-16">
                        <input 
                          type="number" step="any" placeholder="Qty"
                          value={ing.quantity || ''} 
                          onChange={e => handleSandboxChange(idx, 'quantity', e.target.value)}
                          className="w-full px-2 py-1.5 bg-[var(--color-meza-surface)] border border-[var(--color-meza-border)] rounded-sm outline-none focus:border-[var(--color-meza-primary)] font-semibold text-xs text-center"
                        />
                      </div>
                      <div className="w-16">
                        <select 
                          value={ing.unit || 'g'} 
                          onChange={e => handleSandboxChange(idx, 'unit', e.target.value)}
                          className="w-full px-1 py-1.5 bg-[var(--color-meza-surface)] border border-[var(--color-meza-border)] rounded-sm outline-none focus:border-[var(--color-meza-primary)] font-semibold text-xs"
                        >
                          <option value="g">g</option>
                          <option value="ml">ml</option>
                          <option value="kg">kg</option>
                          <option value="L">L</option>
                          <option value="pcs">pcs</option>
                        </select>
                      </div>
                      <button 
                        onClick={() => handleRemoveSandboxIngredient(idx)}
                        className="p-1.5 text-[var(--color-meza-muted)] hover:text-[var(--color-danger)] hover:bg-[var(--color-danger)]/10 rounded-sm transition-colors"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>
                  ))
                )}
              </div>
            </div>
          )}
        </div>

        {/* RIGHT COLUMN: ITEMS LIST */}
        <div className="bg-[var(--color-meza-surface)] rounded-sm shadow-[0_2px_10px_rgb(0,0,0,0.02)] border border-[var(--color-meza-border)] overflow-hidden flex flex-col h-[600px]">
          <div className="p-5 border-b border-[var(--color-meza-border)] shrink-0">
            <h3 className="text-sm font-bold text-[var(--color-meza-text)] flex items-center space-x-2 uppercase tracking-wider">
              <Tag className="w-4 h-4 text-[var(--color-meza-primary)]" />
              <span>Menu Items</span>
            </h3>
            <p className="text-xs text-[var(--color-meza-muted)] mt-1 font-medium">Click an item to edit its recipe.</p>
          </div>
          <div className="overflow-x-auto flex-1 overflow-y-auto">
            <table className="w-full text-left text-sm min-w-[500px]">
              <thead className="bg-[var(--color-meza-bg)] border-b border-[var(--color-meza-border)] text-[var(--color-meza-muted)] text-[10px] font-bold uppercase tracking-wider sticky top-0 z-10">
                <tr>
                  <th className="px-6 py-4">Menu Item</th>
                  <th className="px-6 py-4">COGS</th>
                  <th className="px-6 py-4 text-right">Margin</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {marginsData.map(item => {
                  const isExpanded = expandedItem === item._id;

                  return (
                    <tr 
                      key={item._id}
                      onClick={() => toggleExpand(item)}
                      className={`transition-colors cursor-pointer ${isExpanded ? 'bg-[var(--color-meza-primary)]/5' : 'hover:bg-[var(--color-meza-bg)]'}`}
                    >
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-2">
                          {isExpanded ? <ChevronUp className="w-4 h-4 text-[var(--color-meza-primary)]" /> : <ChevronDown className="w-4 h-4 text-[var(--color-meza-muted)]" />}
                          <div>
                            <div className={`font-semibold ${isExpanded ? 'text-[var(--color-meza-primary)]' : 'text-[var(--color-meza-text)]'}`}>{item.name}</div>
                            <div className="text-[10px] font-bold text-[var(--color-meza-muted)] uppercase tracking-widest mt-0.5">Sell: ₱{item.sellPrice.toFixed(2)}</div>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-[var(--color-meza-muted)] font-medium">₱{item.cogs.toFixed(2)}</td>
                      <td className="px-6 py-4 text-right">
                        <span className={`inline-flex items-center px-2.5 py-1 rounded-md text-[11px] font-bold uppercase tracking-wide border ${getMarginColor(item.marginPercent)}`}>
                          {item.marginPercent.toFixed(1)}%
                        </span>
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { AlertTriangle, CheckCircle, FileText, Download, X, Activity, DollarSign, CreditCard, Banknote } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { useSocket } from '../../context/SocketContext';

export default function ShiftHistory() {
  const { token } = useAuth();
  const socket = useSocket();
  const [shifts, setShifts] = useState([]);

  // Analytics Modal State
  const [selectedShift, setSelectedShift] = useState(null);
  const [analyticsData, setAnalyticsData] = useState(null);
  const [loadingAnalytics, setLoadingAnalytics] = useState(false);

  const fetchShifts = () => {
    fetch(`${import.meta.env.VITE_API_URL || (import.meta.env.VITE_API_URL || 'http://localhost:5001')}/api/shifts`, {
      headers: { 'Authorization': `Bearer ${token}` }
    })
      .then(res => res.ok ? res.json() : Promise.reject(new Error(res.statusText)))
      .then(data => {
        if (Array.isArray(data)) setShifts(data);
        else setShifts([]);
      })
      .catch(console.error);
  };

  useEffect(() => {
    if (token) fetchShifts();
  }, [token]);

  // Real-time socket sync
  useEffect(() => {
    if (!socket) return;

    const handleShiftUpdated = () => {
      fetchShifts();
      // If modal is open, we could also refresh the analytics, but simpler to just fetchShifts
    };

    socket.on('shift:updated', handleShiftUpdated);
    return () => {
      socket.off('shift:updated', handleShiftUpdated);
    };
  }, [socket, token]);

  const formatDateTime = (dateString) => {
    if (!dateString) return 'Ongoing';
    return new Date(dateString).toLocaleString('en-PH', { 
      month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'
    });
  };

  const handleOpenAnalytics = async (shift) => {
    setSelectedShift(shift);
    setLoadingAnalytics(true);
    setAnalyticsData(null);

    try {
      const res = await fetch(`${import.meta.env.VITE_API_URL || `${import.meta.env.VITE_API_URL || (import.meta.env.VITE_API_URL || 'http://localhost:5001')}`}/api/shifts/${shift._id}/analytics`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setAnalyticsData(data);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoadingAnalytics(false);
    }
  };

  const downloadCSV = () => {
    if (!analyticsData) return;
    const { shift, analytics } = analyticsData;

    let csv = `Shift Analytics Report\n`;
    csv += `Staff,${shift.staff?.name || 'Unknown'}\n`;
    csv += `Start Time,${formatDateTime(shift.startTime)}\n`;
    csv += `End Time,${formatDateTime(shift.endTime)}\n`;
    csv += `Status,${shift.status}\n\n`;

    csv += `Financial Summary\n`;
    csv += `Total Revenue,${analytics.totalSales.toFixed(2)}\n`;
    csv += `Total Orders,${analytics.totalOrders}\n`;
    csv += `Cash Payments,${analytics.cashSales.toFixed(2)}\n`;
    csv += `Card Payments,${analytics.cardSales.toFixed(2)}\n`;
    csv += `GCash Payments,${analytics.gcashSales.toFixed(2)}\n\n`;

    csv += `Register Tally\n`;
    csv += `Starting Cash Float,${shift.startingCash.toFixed(2)}\n`;
    csv += `Expected Cash in Drawer,${shift.expectedCash ? shift.expectedCash.toFixed(2) : 'Tallying'}\n`;
    csv += `Actual Cash Counted,${shift.actualCash ? shift.actualCash.toFixed(2) : 'Tallying'}\n`;
    const diff = shift.status === 'closed' ? shift.actualCash - shift.expectedCash : 0;
    csv += `Discrepancy,${diff.toFixed(2)}\n\n`;

    csv += `Items Sold\n`;
    csv += `Item Name,Quantity Sold,Revenue Generated\n`;
    analytics.topItems.forEach(item => {
      csv += `"${item.name}",${item.qty},${item.revenue.toFixed(2)}\n`;
    });

    const blob = new Blob([csv], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.setAttribute('href', url);
    a.setAttribute('download', `Shift_Report_${shift._id}.csv`);
    a.click();
  };

  return (
    <div className="space-y-6 relative">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-[var(--color-meza-text)] tracking-tight">Shift Tracking</h2>
          <p className="text-[var(--color-meza-muted)] text-sm mt-1">Real-time live cash tracking, register discrepancies, and detailed shift analytics.</p>
        </div>
      </div>

      <div className="bg-[var(--color-meza-surface)] rounded-sm shadow-[0_4px_20px_rgb(0,0,0,0.03)] border border-[var(--color-meza-border)] overflow-hidden">
        <div className="p-5 border-b border-[var(--color-meza-border)] flex items-center justify-between bg-[var(--color-meza-bg)]">
          <h3 className="font-bold text-[var(--color-meza-text)] text-sm uppercase tracking-wider">Historical Log</h3>
          <div className="flex items-center space-x-2 text-xs font-semibold text-[var(--color-meza-primary)] bg-[var(--color-meza-primary)]/10 px-2.5 py-1 rounded-md border border-[var(--color-meza-primary)]/20">
            <Activity className="w-3 h-3 animate-pulse" />
            <span>Live Sync Active</span>
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-[var(--color-meza-surface)] border-b border-[var(--color-meza-border)] text-[var(--color-meza-muted)] text-[11px] font-bold uppercase tracking-widest">
              <tr>
                <th className="px-6 py-4">Timeframe</th>
                <th className="px-6 py-4">Cashier</th>
                <th className="px-6 py-4">Starting Money</th>
                <th className="px-6 py-4">Expected Cash</th>
                <th className="px-6 py-4">Actual Drawer</th>
                <th className="px-6 py-4 text-right">Discrepancy</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {Array.isArray(shifts) && shifts.length > 0 ? shifts.map((shift) => {
                const isClosed = shift.status === 'closed';
                const expected = shift.expectedCash || 0;
                const actual = shift.actualCash || 0;
                const diff = isClosed ? actual - expected : 0;
                const hasDiscrepancy = Math.abs(diff) > 1; // Allow 1 peso wiggle room

                return (
                  <tr 
                    key={shift._id} 
                    className="hover:bg-[var(--color-meza-bg)] transition-colors cursor-pointer group"
                    onClick={() => handleOpenAnalytics(shift)}
                  >
                    <td className="px-6 py-4">
                      <div className="flex items-start space-x-2">
                        <div className="flex flex-col items-center mt-1">
                          <div className="w-2 h-2 rounded-full bg-[var(--color-success)]/100"></div>
                          <div className="w-0.5 h-3 bg-[var(--color-meza-border)] my-0.5"></div>
                          <div className={`w-2 h-2 rounded-full ${isClosed ? 'bg-[var(--color-danger)]/100' : 'bg-gray-300 animate-pulse'}`}></div>
                        </div>
                        <div className="flex flex-col text-xs font-medium">
                          <span className="text-[var(--color-meza-text)]">{formatDateTime(shift.startTime)}</span>
                          <span className={`${isClosed ? 'text-[var(--color-meza-muted)]' : 'text-[var(--color-meza-primary)]'} mt-1`}>{formatDateTime(shift.endTime)}</span>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="font-semibold text-[var(--color-meza-text)]">{shift.staff?.name || 'Unknown'}</span>
                      <span className={`ml-2 inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wide border ${
                        isClosed ? 'bg-[var(--color-meza-bg)] text-[var(--color-meza-muted)] border-[var(--color-meza-border)]' : 'bg-[var(--color-meza-primary)]/10 text-[var(--color-meza-primary)] border-[var(--color-meza-primary)]/20'
                      }`}>
                        {shift.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 font-bold text-[var(--color-meza-muted)]">
                      ₱{(shift.startingCash || 0).toFixed(2)}
                    </td>
                    <td className="px-6 py-4 font-medium text-[var(--color-meza-muted)]">
                      {isClosed ? `₱${expected.toFixed(2)}` : 'Tallying...'}
                    </td>
                    <td className="px-6 py-4 font-bold text-[var(--color-meza-text)]">
                      {isClosed ? `₱${actual.toFixed(2)}` : 'Register Open'}
                    </td>
                    <td className="px-6 py-4 text-right">
                      {!isClosed ? (
                        <span className="text-[var(--color-meza-muted)] font-medium italic">Pending</span>
                      ) : hasDiscrepancy ? (
                        <span className={`inline-flex items-center space-x-1 px-2.5 py-1 rounded-md text-[11px] font-bold uppercase tracking-wide border ${
                          diff < 0 ? 'bg-[var(--color-danger)]/10/80 text-[var(--color-danger)] border-[var(--color-danger)]/30/60' : 'bg-[var(--color-warning)]/10/80 text-[var(--color-warning)] border-[var(--color-warning)]/30/60'
                        }`}>
                          <AlertTriangle className="w-3 h-3" strokeWidth={3} />
                          <span>{diff < 0 ? 'Short' : 'Overage'} ₱{Math.abs(diff).toFixed(2)}</span>
                        </span>
                      ) : (
                        <span className="inline-flex items-center space-x-1 px-2.5 py-1 rounded-md text-[11px] font-bold uppercase tracking-wide border bg-[var(--color-success)]/10/80 text-[var(--color-success)] border-[var(--color-success)]/30/60">
                          <CheckCircle className="w-3 h-3" strokeWidth={3} />
                          <span>Exact Match</span>
                        </span>
                      )}
                    </td>
                  </tr>
                );
              }) : (
                <tr>
                  <td colSpan="5" className="px-6 py-12 text-center text-[var(--color-meza-muted)] font-medium text-sm">
                    No shift history available.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Analytics Modal */}
      {selectedShift && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-meza-text/40 backdrop-blur-sm p-4">
          <div className="bg-[var(--color-meza-surface)] rounded-sm w-full max-w-2xl  overflow-hidden border border-[var(--color-meza-border)] transform transition-all flex flex-col max-h-[90vh]">
            <div className="flex justify-between items-center p-5 border-b border-[var(--color-meza-border)] bg-[var(--color-meza-bg)]">
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 rounded-full bg-[var(--color-meza-primary)]/10 text-[var(--color-meza-primary)] flex items-center justify-center font-bold">
                  {selectedShift.staff?.name?.charAt(0) || 'U'}
                </div>
                <div>
                  <h3 className="font-bold text-[var(--color-meza-text)] text-lg leading-tight">Shift Analytics</h3>
                  <p className="text-xs text-[var(--color-meza-muted)] font-medium">{formatDateTime(selectedShift.startTime)} — {formatDateTime(selectedShift.endTime)}</p>
                </div>
              </div>
              <div className="flex items-center space-x-2">
                <button 
                  onClick={downloadCSV}
                  disabled={loadingAnalytics || !analyticsData}
                  className="px-3 py-1.5 bg-[var(--color-meza-bg)] hover:bg-[var(--color-meza-border)] text-[var(--color-meza-text)] rounded-sm text-sm font-bold flex items-center space-x-2 transition-colors disabled:opacity-50"
                >
                  <Download className="w-4 h-4" />
                  <span>Export CSV</span>
                </button>
                <button onClick={() => setSelectedShift(null)} className="p-1.5 text-[var(--color-meza-muted)] hover:text-[var(--color-meza-muted)] hover:bg-[var(--color-meza-bg)] rounded-sm transition-colors">
                  <X className="w-5 h-5" />
                </button>
              </div>
            </div>

            <div className="p-6 overflow-y-auto">
              {loadingAnalytics ? (
                <div className="py-12 flex justify-center text-[var(--color-meza-muted)]">
                  <Activity className="w-8 h-8 animate-spin" />
                </div>
              ) : analyticsData ? (
                <div className="space-y-6">

                  {/* KPI Cards */}
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                    <div className="p-4 bg-[var(--color-meza-bg)] rounded-sm border border-[var(--color-meza-border)] text-center">
                      <div className="text-[10px] font-bold text-[var(--color-meza-muted)] uppercase tracking-wider mb-1">Starting Money</div>
                      <div className="text-xl font-bold text-[var(--color-meza-text)]">₱{(analyticsData.shift.startingCash || 0).toFixed(2)}</div>
                    </div>
                    <div className="p-4 bg-[var(--color-success)]/10 rounded-sm border border-green-100 text-center">
                      <div className="text-[10px] font-bold text-[var(--color-success)] uppercase tracking-wider mb-1">Total Revenue</div>
                      <div className="text-xl font-bold text-[var(--color-success)]">₱{analyticsData.analytics.totalSales.toFixed(2)}</div>
                    </div>
                    <div className="p-4 bg-[var(--color-meza-primary)]/10 rounded-sm border border-blue-100 text-center">
                      <div className="text-[10px] font-bold text-[var(--color-meza-primary)] uppercase tracking-wider mb-1">Items Sold</div>
                      <div className="text-xl font-bold text-[var(--color-meza-primary)]">{analyticsData.analytics.topItems.reduce((acc, curr) => acc + curr.qty, 0)} items</div>
                    </div>
                    <div className="p-4 bg-[var(--color-warning)]/10 rounded-sm border border-yellow-100 text-center">
                      <div className="text-[10px] font-bold text-[var(--color-warning)] uppercase tracking-wider mb-1">Ending Cash</div>
                      <div className="text-xl font-bold text-[var(--color-warning)]">₱{analyticsData.shift.actualCash ? analyticsData.shift.actualCash.toFixed(2) : '--'}</div>
                    </div>
                  </div>

                  {/* Payment Breakdown */}
                  <div>
                    <h4 className="text-xs font-bold text-[var(--color-meza-muted)] uppercase tracking-wider mb-3">Payment Methods</h4>
                    <div className="bg-[var(--color-meza-surface)] border border-[var(--color-meza-border)] rounded-sm p-4 flex justify-between">
                      <div className="flex items-center space-x-3">
                        <div className="w-8 h-8 rounded-sm bg-[var(--color-success)]/10 text-[var(--color-success)] flex items-center justify-center"><Banknote className="w-4 h-4" /></div>
                        <div>
                          <p className="text-sm font-bold text-[var(--color-meza-text)]">Cash</p>
                          <p className="text-xs text-[var(--color-meza-muted)]">₱{analyticsData.analytics.cashSales.toFixed(2)}</p>
                        </div>
                      </div>
                      <div className="flex items-center space-x-3">
                        <div className="w-8 h-8 rounded-sm bg-[var(--color-meza-primary)]/10 text-[var(--color-meza-primary)] flex items-center justify-center"><CreditCard className="w-4 h-4" /></div>
                        <div>
                          <p className="text-sm font-bold text-[var(--color-meza-text)]">Card</p>
                          <p className="text-xs text-[var(--color-meza-muted)]">₱{analyticsData.analytics.cardSales.toFixed(2)}</p>
                        </div>
                      </div>
                      <div className="flex items-center space-x-3">
                        <div className="w-8 h-8 rounded-sm bg-indigo-50 text-indigo-600 flex items-center justify-center"><span className="font-bold text-xs">G</span></div>
                        <div>
                          <p className="text-sm font-bold text-[var(--color-meza-text)]">GCash</p>
                          <p className="text-xs text-[var(--color-meza-muted)]">₱{analyticsData.analytics.gcashSales.toFixed(2)}</p>
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* Top Items Table */}
                  <div>
                    <h4 className="text-xs font-bold text-[var(--color-meza-muted)] uppercase tracking-wider mb-3">Items Sold</h4>
                    <div className="border border-[var(--color-meza-border)] rounded-sm overflow-hidden">
                      <table className="w-full text-left text-sm">
                        <thead className="bg-[var(--color-meza-bg)] text-[var(--color-meza-muted)] text-[10px] uppercase font-bold">
                          <tr>
                            <th className="px-4 py-2">Item Name</th>
                            <th className="px-4 py-2 text-right">Qty</th>
                            <th className="px-4 py-2 text-right">Revenue</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                          {analyticsData.analytics.topItems.map((item, idx) => (
                            <tr key={idx}>
                              <td className="px-4 py-3 font-semibold text-[var(--color-meza-text)]">{item.name}</td>
                              <td className="px-4 py-3 text-right font-medium text-[var(--color-meza-muted)]">{item.qty}</td>
                              <td className="px-4 py-3 text-right font-bold text-[var(--color-meza-text)]">₱{item.revenue.toFixed(2)}</td>
                            </tr>
                          ))}
                          {analyticsData.analytics.topItems.length === 0 && (
                            <tr><td colSpan="3" className="px-4 py-6 text-center text-[var(--color-meza-muted)]">No items sold during this shift.</td></tr>
                          )}
                        </tbody>
                      </table>
                    </div>
                  </div>

                  {/* Transaction History */}
                  <div>
                    <h4 className="text-xs font-bold text-[var(--color-meza-muted)] uppercase tracking-wider mb-3">Transaction History</h4>
                    <div className="border border-[var(--color-meza-border)] rounded-sm overflow-hidden">
                      <table className="w-full text-left text-sm">
                        <thead className="bg-[var(--color-meza-bg)] text-[var(--color-meza-muted)] text-[10px] uppercase font-bold">
                          <tr>
                            <th className="px-4 py-2">Time</th>
                            <th className="px-4 py-2">Order ID</th>
                            <th className="px-4 py-2">Items</th>
                            <th className="px-4 py-2 text-right">Method</th>
                            <th className="px-4 py-2 text-right">Total</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                          {analyticsData.analytics.orders && analyticsData.analytics.orders.length > 0 ? (
                            analyticsData.analytics.orders.map(order => (
                              <tr key={order._id} className="hover:bg-[var(--color-meza-bg)]">
                                <td className="px-4 py-3 font-medium text-[var(--color-meza-muted)]">{new Date(order.createdAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</td>
                                <td className="px-4 py-3">
                                  <div className="font-bold text-[var(--color-meza-text)]">#{order._id.slice(-4).toUpperCase()}</div>
                                  {order.customerName && <div className="text-xs text-[var(--color-meza-muted)] font-normal">{order.customerName}</div>}
                                </td>
                                <td className="px-4 py-3 text-[var(--color-meza-muted)] text-xs">
                                  {order.items.map(i => (
                                    <div key={i._id || i.menuItemId}>
                                      {i.quantity}x {i.nameAtSale} - ₱{((i.priceAtSale || 0) * (i.quantity || 1)).toFixed(2)}
                                    </div>
                                  ))}
                                </td>
                                <td className="px-4 py-3 text-right">
                                  <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded ${order.paymentMethod === 'cash' ? 'bg-[var(--color-success)]/20 text-[var(--color-success)]' : 'bg-[var(--color-meza-primary)]/20 text-[var(--color-meza-primary)]'}`}>
                                    {order.paymentMethod}
                                  </span>
                                </td>
                                <td className="px-4 py-3 text-right font-bold text-[var(--color-meza-text)]">₱{order.total.toFixed(2)}</td>
                              </tr>
                            ))
                          ) : (
                            <tr><td colSpan="5" className="px-4 py-6 text-center text-[var(--color-meza-muted)]">No transactions recorded.</td></tr>
                          )}
                        </tbody>
                      </table>
                    </div>
                  </div>

                </div>
              ) : null}
            </div>
          </div>
        </div>
      )}

    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Users, Shield, Plus, Edit2, KeyRound, Lock, UserCheck, UserX, X, Save } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';

export default function StaffManagement() {
  const { token, user: currentUser } = useAuth();
  const [staff, setStaff] = useState([]);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState('add'); // 'add', 'edit'
  const [editingStaff, setEditingStaff] = useState(null);

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    role: 'cashier',
    password: '',
    pin: '',
    isActive: true
  });

  const fetchStaff = () => {
    fetch(`${import.meta.env.VITE_API_URL || (import.meta.env.VITE_API_URL || 'http://localhost:5001')}/api/users`, {
      headers: { 'Authorization': `Bearer ${token}` }
    })
      .then(res => res.ok ? res.json() : Promise.reject(new Error(res.statusText)))
      .then(data => {
        if (Array.isArray(data)) setStaff(data);
      })
      .catch(console.error);
  };

  useEffect(() => {
    if (token) fetchStaff();
  }, [token]);

  const openAddModal = () => {
    setModalMode('add');
    setFormData({ name: '', email: '', role: 'cashier', password: '', pin: '', isActive: true });
    setIsModalOpen(true);
  };

  const openEditModal = (user) => {
    setModalMode('edit');
    setEditingStaff(user);
    setFormData({
      name: user.name,
      email: user.email,
      role: user.role,
      isActive: user.isActive,
      password: '', // Blank unless they want to change it
      pin: '' // Blank unless they want to change it
    });
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingStaff(null);
  };

  const handleSaveUser = async (e) => {
    e.preventDefault();
    const url = modalMode === 'edit' ? `${import.meta.env.VITE_API_URL || `${import.meta.env.VITE_API_URL || (import.meta.env.VITE_API_URL || 'http://localhost:5001')}`}/api/users/${editingStaff._id}` : `${import.meta.env.VITE_API_URL || (import.meta.env.VITE_API_URL || 'http://localhost:5001')}/api/users`;
    const method = modalMode === 'edit' ? 'PUT' : 'POST';

    // Validation
    if (modalMode === 'add' && !formData.password) return alert('Password is required for new accounts.');
    if ((formData.role === 'manager' || formData.role === 'owner') && modalMode === 'add' && !formData.pin) {
      return alert('A 4-digit PIN is required for Managers and Owners.');
    }

    // Build payload (only send password/pin if they typed something)
    const payload = { ...formData };
    if (!payload.password) delete payload.password;
    if (!payload.pin) delete payload.pin;

    try {
      const res = await fetch(url, {
        method,
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify(payload)
      });

      if (res.ok) {
        fetchStaff();
        handleCloseModal();
      } else {
        const errData = await res.json();
        alert(`Failed: ${errData.message || 'Unknown error'}`);
      }
    } catch (err) {
      console.error(err);
      alert('Network error');
    }
  };

  const handleToggleStatus = async (user) => {
    if (user._id === currentUser.id) return alert("You cannot deactivate yourself.");

    try {
      const res = await fetch(`${import.meta.env.VITE_API_URL || `${import.meta.env.VITE_API_URL || (import.meta.env.VITE_API_URL || 'http://localhost:5001')}`}/api/users/${user._id}`, {
        method: 'PUT',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ isActive: !user.isActive })
      });
      if (res.ok) fetchStaff();
    } catch (err) { console.error(err); }
  };

  const getRoleBadge = (role) => {
    if (role === 'owner') return 'bg-purple-50 text-purple-700 border-purple-200';
    if (role === 'manager') return 'bg-[var(--color-meza-primary)]/10 text-[var(--color-meza-primary)] border-[var(--color-meza-primary)]/30';
    return 'bg-[var(--color-meza-bg)] text-[var(--color-meza-muted)] border-[var(--color-meza-border)]';
  };

  const isOwner = currentUser?.role === 'owner';

  return (
    <div className="space-y-6 relative">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-[var(--color-meza-text)] tracking-tight">Staff Management</h2>
          <p className="text-[var(--color-meza-muted)] text-sm mt-1">Manage system access, roles, and authorization PINs.</p>
        </div>
        {isOwner && (
          <button onClick={openAddModal} className="bg-meza-text hover:bg-[var(--color-meza-primary)] text-white px-5 py-2.5 rounded-sm flex items-center space-x-2 font-bold text-sm transition-all  hover: active:scale-[0.98]">
            <Plus className="w-4 h-4" strokeWidth={2.5} />
            <span>Add Staff Member</span>
          </button>
        )}
      </div>

      <div className="bg-[var(--color-meza-surface)] rounded-sm shadow-[0_4px_20px_rgb(0,0,0,0.03)] border border-[var(--color-meza-border)] overflow-hidden flex flex-col">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-[var(--color-meza-bg)] border-b border-[var(--color-meza-border)] text-[var(--color-meza-muted)] text-[11px] font-bold uppercase tracking-widest">
              <tr>
                <th className="px-6 py-4">Staff Member</th>
                <th className="px-6 py-4">Contact</th>
                <th className="px-6 py-4">System Role</th>
                <th className="px-6 py-4">Status</th>
                {isOwner && <th className="px-6 py-4 text-right">Actions</th>}
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {staff.map(user => (
                <tr key={user._id} className={`hover:bg-[var(--color-meza-bg)]/50 transition-colors group ${!user.isActive ? 'opacity-60' : ''}`}>
                  <td className="px-6 py-4">
                    <div className="flex items-center space-x-3">
                      <div className="w-10 h-10 rounded-full bg-[var(--color-meza-primary)]/10 text-[var(--color-meza-primary)] flex items-center justify-center font-bold text-lg">
                        {user.name.charAt(0).toUpperCase()}
                      </div>
                      <div className="flex flex-col">
                        <span className="font-bold text-[var(--color-meza-text)]">{user.name}</span>
                        {user._id === currentUser.id && (
                          <span className="text-[10px] font-bold text-[var(--color-meza-primary)] uppercase tracking-wider">(You)</span>
                        )}
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 font-medium text-[var(--color-meza-muted)]">{user.email}</td>
                  <td className="px-6 py-4">
                    <span className={`inline-flex items-center space-x-1.5 px-2.5 py-1 rounded-md text-[10px] font-bold uppercase tracking-wider border ${getRoleBadge(user.role)}`}>
                      <Shield className="w-3 h-3" strokeWidth={2.5} />
                      <span>{user.role}</span>
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    {user.isActive ? (
                      <span className="inline-flex items-center space-x-1.5 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider border bg-[var(--color-success)]/10 text-[var(--color-success)] border-green-100">
                        <UserCheck className="w-3 h-3" strokeWidth={2.5} />
                        <span>Active</span>
                      </span>
                    ) : (
                      <span className="inline-flex items-center space-x-1.5 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider border bg-[var(--color-meza-bg)] text-[var(--color-meza-muted)] border-[var(--color-meza-border)]">
                        <UserX className="w-3 h-3" strokeWidth={2.5} />
                        <span>Suspended</span>
                      </span>
                    )}
                  </td>
                  {isOwner && (
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end space-x-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={() => handleToggleStatus(user)} 
                          disabled={user._id === currentUser.id}
                          className="px-3 py-1.5 bg-[var(--color-meza-bg)] hover:bg-[var(--color-meza-border)] text-[var(--color-meza-muted)] rounded-sm text-xs font-bold transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                          {user.isActive ? 'Suspend' : 'Reactivate'}
                        </button>
                        <button 
                          onClick={() => openEditModal(user)} 
                          className="p-1.5 bg-[var(--color-meza-bg)] text-[var(--color-meza-muted)] hover:bg-[var(--color-meza-primary)] hover:text-white rounded-sm transition-colors "
                        >
                          <Edit2 className="w-4 h-4" />
                        </button>
                      </div>
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add / Edit Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-meza-text/40 backdrop-blur-sm p-4">
          <div className="bg-[var(--color-meza-surface)] rounded-sm w-full max-w-md  overflow-hidden border border-[var(--color-meza-border)] transform transition-all">
            <div className="flex justify-between items-center p-5 border-b border-[var(--color-meza-border)] bg-[var(--color-meza-bg)]">
              <div className="flex items-center space-x-2">
                <Users className="w-5 h-5 text-[var(--color-meza-primary)]" />
                <h3 className="font-bold text-[var(--color-meza-text)] text-lg">
                  {modalMode === 'add' ? 'Create Staff Account' : 'Edit Staff Member'}
                </h3>
              </div>
              <button onClick={handleCloseModal} className="p-1.5 text-[var(--color-meza-muted)] hover:text-[var(--color-meza-muted)] hover:bg-[var(--color-meza-bg)] rounded-sm transition-colors"><X className="w-5 h-5" /></button>
            </div>

            <form onSubmit={handleSaveUser} className="p-6 space-y-4">
              <div>
                <label className="block text-[11px] font-bold text-[var(--color-meza-muted)] uppercase tracking-wider mb-1.5">Full Name</label>
                <input type="text" required value={formData.name} onChange={e=>setFormData({...formData, name: e.target.value})} className="w-full px-4 py-2.5 bg-[var(--color-meza-bg)] border border-[var(--color-meza-border)] rounded-sm outline-none focus:border-[var(--color-meza-primary)] focus:ring-2 focus:ring-[var(--color-meza-primary)]/10 font-semibold text-[var(--color-meza-text)]" placeholder="John Doe" />
              </div>

              <div>
                <label className="block text-[11px] font-bold text-[var(--color-meza-muted)] uppercase tracking-wider mb-1.5">Email Address (Login ID)</label>
                <input type="email" required value={formData.email} onChange={e=>setFormData({...formData, email: e.target.value})} className="w-full px-4 py-2.5 bg-[var(--color-meza-bg)] border border-[var(--color-meza-border)] rounded-sm outline-none focus:border-[var(--color-meza-primary)] focus:ring-2 focus:ring-[var(--color-meza-primary)]/10 font-semibold text-[var(--color-meza-text)]" placeholder="john@meza.cafe" />
              </div>

              <div>
                <label className="block text-[11px] font-bold text-[var(--color-meza-muted)] uppercase tracking-wider mb-1.5">System Role</label>
                <select required value={formData.role} onChange={e=>setFormData({...formData, role: e.target.value})} className="w-full px-4 py-2.5 bg-[var(--color-meza-bg)] border border-[var(--color-meza-border)] rounded-sm outline-none focus:border-[var(--color-meza-primary)] focus:ring-2 focus:ring-[var(--color-meza-primary)]/10 font-semibold text-[var(--color-meza-text)] appearance-none">
                  <option value="cashier">Cashier (POS Only)</option>
                  <option value="manager">Store Manager</option>
                  <option value="owner">Owner (Full Access)</option>
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4 pt-2">
                <div>
                  <label className="block text-[11px] font-bold text-[var(--color-meza-muted)] uppercase tracking-wider mb-1.5 flex items-center space-x-1">
                    <KeyRound className="w-3 h-3" /> <span>Password</span>
                  </label>
                  <input type="password" value={formData.password} onChange={e=>setFormData({...formData, password: e.target.value})} placeholder={modalMode === 'edit' ? "Leave blank to keep" : "••••••••"} className="w-full px-4 py-2.5 bg-[var(--color-meza-bg)] border border-[var(--color-meza-border)] rounded-sm outline-none focus:border-[var(--color-meza-primary)] focus:ring-2 focus:ring-[var(--color-meza-primary)]/10 font-semibold text-[var(--color-meza-text)]" />
                </div>
                <div>
                  <label className="block text-[11px] font-bold text-[var(--color-meza-muted)] uppercase tracking-wider mb-1.5 flex items-center space-x-1">
                    <Lock className="w-3 h-3" /> <span>Manager PIN</span>
                  </label>
                  <input 
                    type="password" 
                    maxLength="4"
                    disabled={formData.role === 'cashier'}
                    value={formData.pin} 
                    onChange={e=>setFormData({...formData, pin: e.target.value.replace(/[^0-9]/g, '')})} 
                    placeholder={formData.role === 'cashier' ? 'N/A' : (modalMode === 'edit' ? "Leave blank to keep" : "4-Digit PIN")} 
                    className="w-full px-4 py-2.5 bg-[var(--color-meza-bg)] border border-[var(--color-meza-border)] rounded-sm outline-none focus:border-[var(--color-meza-primary)] focus:ring-2 focus:ring-[var(--color-meza-primary)]/10 font-semibold text-[var(--color-meza-text)] disabled:opacity-50 disabled:cursor-not-allowed" 
                  />
                </div>
              </div>

              <div className="pt-4 border-t border-[var(--color-meza-border)] mt-6 flex justify-end space-x-3">
                <button type="button" onClick={handleCloseModal} className="px-5 py-2.5 text-[var(--color-meza-muted)] hover:bg-[var(--color-meza-bg)] rounded-sm font-bold transition-colors">Cancel</button>
                <button type="submit" className="px-5 py-2.5 bg-meza-text text-white hover:bg-[var(--color-meza-primary)] rounded-sm font-bold flex items-center space-x-2 transition-colors ">
                  <Save className="w-4 h-4" /><span>{modalMode === 'add' ? 'Create Account' : 'Save Changes'}</span>
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

